"use strict";parserFactory.register("mottruyen.com.vn",()=>new MottruyenParser),parserFactory.register("mottruyen.vn",()=>new MottruyenParser);class MottruyenParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=t.baseURI.split("/").filter(t=>""!=t),r=e[e.length-1],s=(await HttpClient.fetchJson("https://api.mottruyen.vn/api/v1/story/"+r)).json,n=s.countChapter,o=s.slug;return(await HttpClient.fetchJson("https://api.mottruyen.vn/api/v1/story/"+r+"/chapter?size="+n+"&page=0&sort=asc")).json.data.map(t=>({sourceUrl:"https://mottruyen.com.vn/"+o+"/"+r+"/chuong/"+t.chapter,title:t.chapterTitle?"Chương "+t.chapter+" :"+t.chapterTitle:"Chương "+t.chapter,isIncludeable:0==t.price}))}async loadEpubMetaInfo(t){let e=t.baseURI.split("/").filter(t=>""!=t),r=e[e.length-1],s=(await HttpClient.fetchJson("https://api.mottruyen.vn/api/v1/story/"+r)).json;this.title=s.name,this.author=s.author.name,this.description=s.introduce?.trim(),this.password=s.password,this.img="https://api.mottruyen.vn/api/v1/storage"+s.image}extractTitleImpl(){return this.title}extractAuthor(){return this.author}extractDescription(){return this.description}findCoverImageUrl(){return this.img}findContent(t){return Parser.findConstrutedContent(t)}async fetchChapter(t){let e=this.toRestUrl(t),r={parser:this},s=(await HttpClient.fetchJson(e,r)).json;return this.buildChapter(s,t)}toRestUrl(t){let e=t.split("/").filter(t=>""!=t);return"https://api.mottruyen.vn/api/v1/story/"+e[e.length-3]+"/chapter/"+e[e.length-1]+"?password="+this.password}isCustomError(t){return!!t?.json?.lock||200!=t?.json?.statusCode}setCustomErrorResponse(t,e,r){if(r?.json?.lock){let s={};return s.url=t,s.wrapOptions=e,s.response={},s.response.url=this.PostToUrl(r.response.url,r),s.response.status=999,s.response.retryDelay=[1],s.errorMessage="This Chapter '"+s.response.url+"' could not be downloaded\nMessage: "+r?.json.content,s}if(200!=r?.json?.statusCode){let s={};return s.url=t,s.wrapOptions=e,s.response={},s.response.url=r.response.url,s.response.status=r?.json?.statusCode,s}}PostToUrl(t,e){let r=t.split("/").filter(t=>""!=t),s=r[r.length-3],n=r[r.length-1];return"https://mottruyen.com.vn/"+e?.json?.nameIndex+"/"+s+"/chuong/"+n}buildChapter(t,e){let r=Parser.makeEmptyDocForContent(e),s=r.dom.createElement("h1");s.textContent=t.chapterTitle?"Chương "+t.chapter+" :"+t.chapterTitle:"Chương "+t.chapter,r.content.appendChild(s);let n=util.sanitize(t.content);return util.moveChildElements(n.body,r.content),r.dom}}